package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.Field;

class GsonBuilderTest {

  @Test
  void testSerializeSpecialFloatingPointValues() throws Exception {
    GsonBuilder gsonBuilder = new GsonBuilder();

    // Before calling serializeSpecialFloatingPointValues(), field should be default false or DEFAULT_SPECIALIZE_FLOAT_VALUES
    Field field = GsonBuilder.class.getDeclaredField("serializeSpecialFloatingPointValues");
    field.setAccessible(true);
    boolean beforeValue = (boolean) field.get(gsonBuilder);

    // Call the focal method
    GsonBuilder returned = gsonBuilder.serializeSpecialFloatingPointValues();

    // Assert method returns this (same instance)
    assertSame(gsonBuilder, returned);

    // Assert the private field is set to true
    boolean afterValue = (boolean) field.get(gsonBuilder);
    assertTrue(afterValue);

    // If default was false, assert changed from false to true
    if (!beforeValue) {
      assertNotEquals(beforeValue, afterValue);
    }
  }
}
